1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	};
8	
9	type Item = { type: string };
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type Step = QuoteStep;
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	
14	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
15	
16	const quotePremium = (items: Item[]): number =>
17	  items.reduce((sum, item) => sum + basePremiumFor(item), 0) + PROCESSING_FEE;
18	
19	export const processScenario = (scenario: Scenario): unknown => {
20	  const results = scenario.steps.map((step) => ({
21	    premium: quotePremium(step.items),
22	  }));
23	  return { results };
24	};
