21	    const result = processScenario({
22	      customer: { yearsWithMHPCO: 0 },
23	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 65 }] });
